from flask import Flask, redirect, request, session
import requests

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Replace with your authorization server details
AUTH_SERVER_URL = 'https://auth.example.com'
CLIENT_ID = 'your_client_id'
REDIRECT_URI = 'http://localhost:5000/callback'

@app.route('/login')
def login():
    state = generate_state()
    session['state'] = state
    auth_url = f'{AUTH_SERVER_URL}/authorize?response_type=code&client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&state={state}'
    return redirect(auth_url)

@app.route('/callback')
def callback():
    if 'state' not in session or request.args.get('state') != session['state']:
        return 'Invalid state parameter', 400

    code = request.args.get('code')
    token_response = requests.post(f'{AUTH_SERVER_URL}/token', data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID
    })

    if token_response.status_code == 200:
        access_token = token_response.json().get('access_token')
        session['access_token'] = access_token
        return 'Login successful', 200
    else:
        return 'Failed to exchange code for token', 500

def generate_state():
    import os
    return os.urandom(16).hex()

if __name__ == '__main__':
    app.run(debug=True)